const PLUGIN_BINARY: &str = "rkrlv2.dylib";
#[cfg(target_os = "linux")]
const PLUGIN_BINARY: &str = "rkrlv2.so";
#[cfg(target_os = "windows")]
const PLUGIN_BINARY: &str = "rkrlv2.dll";

// Port indices (from TTL)
const PORT_AUDIO_IN_INPUT_L: usize = 0;
const PORT_AUDIO_IN_INPUT_R: usize = 1;
const PORT_AUDIO_OUT_OUTPUT_L: usize = 2;
const PORT_AUDIO_OUT_OUTPUT_R: usize = 3;
const PORT_CTRL_BYPASS: usize = 4;
const PORT_CTRL_THRESHOLD: usize = 5;
const PORT_CTRL_SHAPE: usize = 6;
const PORT_CTRL_ATTACK: usize = 7;
const PORT_CTRL_RELEASE: usize = 8;
const PORT_CTRL_LPF: usize = 9;
const PORT_CTRL_HPF: usize = 10;
const PORT_CTRL_OUTPUT: usize = 11;

pub fn model_schema() -> ModelParameterSchema {
    ModelParameterSchema {
        effect_type: block_core::EFFECT_TYPE_DYNAMICS.into(),
        model: MODEL_ID.into(),
        display_name: DISPLAY_NAME.into(),
        audio_mode: ModelAudioMode::TrueStereo,
        parameters: vec![
            bool_parameter("bypass", "Bypass", None, Some(false)),
            float_parameter("threshold", "Threshold", None, Some(-30.0), -80.0, 0.0, 0.1, ParameterUnit::Decibels),
            float_parameter("shape", "Shape", None, Some(2.0), 1.0, 50.0, 0.1, ParameterUnit::None),
            float_parameter("attack", "Attack Time", None, Some(20.0), 1.0, 5000.0, 10.0, ParameterUnit::Milliseconds),
            float_parameter("release", "Release Time", None, Some(120.0), 10.0, 1000.0, 1.0, ParameterUnit::Milliseconds),
            float_parameter("lpf", "Lowpass Filter", None, Some(3134.0), 20.0, 26000.0, 10.0, ParameterUnit::Hertz),
            float_parameter("hpf", "Highpass Filter", None, Some(76.0), 20.0, 20000.0, 10.0, ParameterUnit::Hertz),
            float_parameter("output", "Output Gain", None, Some(10.0), 1.0, 127.0, 1.0, ParameterUnit::None),
        ],
    }
}

fn build(params: &ParameterSet, sample_rate: f32, layout: AudioChannelLayout) -> Result<BlockProcessor> {
    let bypass = required_bool(params, "bypass").map_err(anyhow::Error::msg)?;
    let threshold = required_f32(params, "threshold").map_err(anyhow::Error::msg)?;
    let shape = required_f32(params, "shape").map_err(anyhow::Error::msg)?;
    let attack = required_f32(params, "attack").map_err(anyhow::Error::msg)?;
    let release = required_f32(params, "release").map_err(anyhow::Error::msg)?;
    let lpf = required_f32(params, "lpf").map_err(anyhow::Error::msg)?;
    let hpf = required_f32(params, "hpf").map_err(anyhow::Error::msg)?;
    let output = required_f32(params, "output").map_err(anyhow::Error::msg)?;
    let lib_path = lv2::resolve_lv2_lib(PLUGIN_BINARY)?;
    let bundle_path = lv2::resolve_lv2_bundle(PLUGIN_DIR)?;

    let control_ports: &[(usize, f32)] = &[
        (PORT_CTRL_BYPASS, if bypass { 1.0 } else { 0.0 }),
        (PORT_CTRL_THRESHOLD, threshold),
        (PORT_CTRL_SHAPE, shape),
        (PORT_CTRL_ATTACK, attack),
        (PORT_CTRL_RELEASE, release),
        (PORT_CTRL_LPF, lpf),
        (PORT_CTRL_HPF, hpf),
        (PORT_CTRL_OUTPUT, output),
    ];

    let processor = lv2::build_stereo_lv2_processor(&lib_path, PLUGIN_URI, sample_rate as f64, &bundle_path, &[PORT_AUDIO_IN_INPUT_L, PORT_AUDIO_IN_INPUT_R], &[PORT_AUDIO_OUT_OUTPUT_L, PORT_AUDIO_OUT_OUTPUT_R], control_ports)?;
    let _ = layout;
    Ok(BlockProcessor::Stereo(Box::new(processor)))
}

